import{_ as t,o,c as a,ag as s}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Continuous proof of storage","description":"Why a Prova-stored file is more durable than one in S3.","frontmatter":{"description":"Why a Prova-stored file is more durable than one in S3."},"headers":[],"relativePath":"concepts/continuous-proof.md","filePath":"concepts/continuous-proof.md","lastUpdated":1777130260000}'),i={name:"concepts/continuous-proof.md"};function r(n,e,l,h,d,c){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="continuous-proof-of-storage" tabindex="-1">Continuous proof of storage <a class="header-anchor" href="#continuous-proof-of-storage" aria-label="Permalink to &quot;Continuous proof of storage&quot;">​</a></h1><p>S3 has 11 nines of durability. Prova has <strong>continuous, verifiable</strong> durability. That&#39;s a stronger property.</p><h2 id="the-difference" tabindex="-1">The difference <a class="header-anchor" href="#the-difference" aria-label="Permalink to &quot;The difference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>S3 / Backblaze / IPFS pin</th><th>Prova</th></tr></thead><tbody><tr><td><strong>Durability claim</strong></td><td>Vendor-asserted</td><td>Cryptographically verified</td></tr><tr><td><strong>Verification</strong></td><td>None — you trust the vendor</td><td>Every 30 seconds, public proof</td></tr><tr><td><strong>Loss detection</strong></td><td>When you try to read</td><td>Within seconds, on-chain</td></tr><tr><td><strong>Economic backing</strong></td><td>Vendor SLA credits</td><td>Slashed prover stake</td></tr><tr><td><strong>Audit trail</strong></td><td>Internal logs</td><td>Public Ethereum L2</td></tr></tbody></table><p>S3 says <em>&quot;we won&#39;t lose your file&quot;</em> and you take their word for it. Prova says <em>&quot;here is a fresh proof, posted to the public ledger 8 seconds ago, that the bytes you stored are still on the prover&#39;s disk.&quot;</em></p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>Prova uses <strong>PDP</strong> (Provable Data Possession), specifically the variant pioneered by Filecoin and adapted for Base in <code>ProofVerifier.sol</code>.</p><p>Every 30 seconds:</p><ol><li><strong>Challenge.</strong> The on-chain contract emits a pseudo-random challenge — a small set of byte offsets within the piece.</li><li><strong>Prove.</strong> The prover reads those bytes off disk, computes a Merkle proof against the piece-cid, and submits the proof to the contract.</li><li><strong>Verify.</strong> The contract checks the proof matches the on-chain cid. Pass → release payment. Fail → don&#39;t release; if it fails too many times in a row, slash.</li></ol><p>The key property: <strong>the prover cannot fake a proof without actually having the bytes</strong>. The Merkle structure is committed at deal creation, so any byte the prover claims to read has to hash up to the original cid.</p><h2 id="what-every-30-seconds-buys-you" tabindex="-1">What &quot;every 30 seconds&quot; buys you <a class="header-anchor" href="#what-every-30-seconds-buys-you" aria-label="Permalink to &quot;What &quot;every 30 seconds&quot; buys you&quot;">​</a></h2><ul><li><strong>Loss detection in seconds.</strong> If a prover loses your file, the next missed proof tells you within 30 seconds. Compare to S3, where you might not know until you try to read.</li><li><strong>Non-repudiation.</strong> The prover cannot say &quot;we had it, but our logs got corrupted.&quot; There is a public chain of signed proofs.</li><li><strong>Slashing economics.</strong> A prover who deletes your file to save disk loses <em>more</em> in slashed stake than they save. The math is in <a href="./../provers/earnings">Earnings</a>.</li><li><strong>Re-pinning.</strong> When a prover starts failing, the marketplace automatically re-lists the cid. Healthy provers pick it up. Your file is never one disk failure away from being lost.</li></ul><h2 id="why-30-seconds-and-not-say-1-second" tabindex="-1">Why 30 seconds and not, say, 1 second <a class="header-anchor" href="#why-30-seconds-and-not-say-1-second" aria-label="Permalink to &quot;Why 30 seconds and not, say, 1 second&quot;">​</a></h2><p>Compute and gas cost. Each proof is a Base L2 transaction. At 30 second cadence:</p><ul><li>~2,880 proofs per day per deal.</li><li>~$0.003 gas per proof on Base L2.</li><li>~$8.64/day in gas per deal — bounded by the deal&#39;s payment, not the protocol&#39;s.</li></ul><p>Faster cadence is technically possible but reduces the prover&#39;s net margin. We picked 30 seconds as a balance: fast enough to detect failures within a single human attention span, slow enough that the gas cost is a small fraction of the storage fee.</p><h2 id="what-this-is-not" tabindex="-1">What this is <em>not</em> <a class="header-anchor" href="#what-this-is-not" aria-label="Permalink to &quot;What this is _not_&quot;">​</a></h2><ul><li>It&#39;s <strong>not</strong> Proof of Replication. We don&#39;t prove the prover sealed the data into a unique encoded form. PoRep is heavier and the security gain is marginal for non-Sybil-resistant networks.</li><li>It&#39;s <strong>not</strong> zero-knowledge. The prover learns nothing about the challenge ahead of time, but the proof itself is public (and trivially small). If you need privacy on top, encrypt before uploading.</li><li>It&#39;s <strong>not</strong> time-locked. The prover proves the file is <em>currently</em> there, not that it was <em>continuously</em> there since deal start. The two are equivalent in practice (you&#39;d notice the gap), but a paranoid client should index the on-chain proofs themselves.</li></ul><h2 id="audit-trail" tabindex="-1">Audit trail <a class="header-anchor" href="#audit-trail" aria-label="Permalink to &quot;Audit trail&quot;">​</a></h2><p>You can verify any deal&#39;s history:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Get all proofs for a deal</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://prova.network/api/files/</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ci</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/proofs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;authorization: Bearer pk_live_...&quot;</span></span></code></pre></div><p>Returns a stream of <code>{ blockNumber, txHash, proofData, valid }</code> records, one per attempted proof. You can independently re-verify any of them by calling <code>ProofVerifier.verifyProof(...)</code> on Base.</p>`,22)])])}const f=t(i,[["render",r]]);export{u as __pageData,f as default};
